// Barrel re-export for generated SSE types (task 02677).
//
// This file is hand-authored but simply re-exports what ts-rs generates
// under this directory. The generated files themselves have the header
// "This file was generated by [ts-rs]. Do not edit this file manually."
// and are regenerated on every `cargo test` run; `./dev.py check` fails
// if any generated file drifts from the Rust source of truth.
//
// Consumers import from `'../generated/sse'` (see `sseSchemas.ts`,
// `api.ts`) — that path resolves to this barrel file.

export type { SseWireEvent } from './SseWireEvent';
export type { EnrichedMessage } from './EnrichedMessage';
export type { MessageType } from './MessageType';
export type { SseBreadcrumb } from './SseBreadcrumb';
export type { UsageData } from './UsageData';
export type { UserFacingError } from './UserFacingError';
export type { UserFacingErrorKind } from './UserFacingErrorKind';

import type { SseWireEvent } from './SseWireEvent';

// Per-variant data shapes, extracted from the SseWireEvent discriminated
// union by its `type` tag. The wire event type tag and the shape on the
// `data:` line are two sides of the same fact — the tag goes in the SSE
// `event:` line and the remaining fields go in the `data:` JSON. Using
// `Extract` means the client's `addEventListener('init', ...)` handler
// is guaranteed by TSC to consume a payload matching exactly the `init`
// variant of `SseWireEvent`.
export type SseInitData = Omit<Extract<SseWireEvent, { type: 'init' }>, 'type'>;
export type SseMessageData = Omit<Extract<SseWireEvent, { type: 'message' }>, 'type'>;
export type SseMessageUpdatedData = Omit<
  Extract<SseWireEvent, { type: 'message_updated' }>,
  'type'
>;
export type SseStateChangeData = Omit<
  Extract<SseWireEvent, { type: 'state_change' }>,
  'type'
>;
export type SseTokenData = Omit<Extract<SseWireEvent, { type: 'token' }>, 'type'>;
export type SseAgentDoneData = Omit<Extract<SseWireEvent, { type: 'agent_done' }>, 'type'>;
export type SseConversationBecameTerminalData = Omit<
  Extract<SseWireEvent, { type: 'conversation_became_terminal' }>,
  'type'
>;
export type SseConversationUpdateData = Omit<
  Extract<SseWireEvent, { type: 'conversation_update' }>,
  'type'
>;
export type SseErrorData = Omit<Extract<SseWireEvent, { type: 'error' }>, 'type'>;
